import{_ as e,a as t,b as d,c as o,d as n,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as i,o as p,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Tambah Dropbox Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/dropbox.md","filePath":"ms-MY/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"ms-MY/upload/dropbox.md"};function h(b,a,u,m,k,g){return p(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="tambah-dropbox-channel" tabindex="-1">Tambah Dropbox Channel <a class="header-anchor" href="#tambah-dropbox-channel" aria-label="Permalink to &quot;Tambah Dropbox Channel&quot;">​</a></h1><h2 id="perkara-yang-perlu-disediakan-dahulu" tabindex="-1">Perkara Yang Perlu Disediakan Dahulu <a class="header-anchor" href="#perkara-yang-perlu-disediakan-dahulu" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan Dahulu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Mengapa Diperlukan</th></tr></thead><tbody><tr><td>Dropbox account</td><td>Digunakan untuk sign in dan authorize app</td></tr><tr><td>Dropbox app</td><td>Digunakan untuk generate <code>App Key</code> dan <code>App Secret</code></td></tr><tr><td>ImgBed domain anda</td><td>Digunakan untuk OAuth redirect URI</td></tr><tr><td>Available Dropbox storage</td><td>Digunakan sebagai lokasi file storage sebenar</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="step-1-cipta-dropbox-app" tabindex="-1">Step 1: Cipta Dropbox App <a class="header-anchor" href="#step-1-cipta-dropbox-app" aria-label="Permalink to &quot;Step 1: Cipta Dropbox App&quot;">​</a></h3><ol><li>Buka Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Cipta app baharu.</li><li>Untuk access type, pilih:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Beri nama app yang mudah dikenali, contohnya <code>imgbed-app</code>.</li><li>Buka app details page selepas ia dicipta.</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended. Ia sepadan dengan cara ImgBed menyimpan files.</td></tr><tr><td><code>Full Dropbox</code></td><td>Tidak recommended. ImgBed tidak memerlukan full-account access.</td></tr></tbody></table><p><img src="'+e+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-tambah-redirect-uri" tabindex="-1">Step 2: Tambah Redirect URI <a class="header-anchor" href="#step-2-tambah-redirect-uri" aria-label="Permalink to &quot;Step 2: Tambah Redirect URI&quot;">​</a></h3><p>Dalam Dropbox app details page, cari OAuth atau Redirect URI settings dan tambah:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Jika anda menggunakan admin panel dari lebih daripada satu domain, tambah setiap callback URL yang sepadan.</p><p><img src="'+t+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-configure-app-permissions" tabindex="-1">Step 3: Configure App Permissions <a class="header-anchor" href="#step-3-configure-app-permissions" aria-label="Permalink to &quot;Step 3: Configure App Permissions&quot;">​</a></h3><p>Buka tab <code>Permissions</code> dan enable sekurang-kurangnya scopes ini:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>Membaca account dan quota information</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>Membaca file dan folder metadata untuk path checks</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>Mencipta folders dan menulis metadata</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>Upload files. Jika scope ini tiada, error <code>required scope &#39;files.content.write&#39;</code> akan berlaku.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>Membolehkan download, preview dan temporary file links</td></tr></tbody></table><p>Selepas memilih scopes, klik <code>Submit</code> di bahagian bawah halaman.</p><p><img src="'+d+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>Apa Yang Perlu Dibuat</th></tr></thead><tbody><tr><td>Anda menukar scopes</td><td>Jalankan token authorization flow semula dan dapatkan <code>Refresh Token</code> baharu.</td></tr><tr><td>Anda tidak reauthorize</td><td>Token lama tidak akan mendapat permissions baharu, jadi uploads masih boleh gagal.</td></tr></tbody></table><h3 id="step-4-copy-app-credentials" tabindex="-1">Step 4: Copy App Credentials <a class="header-anchor" href="#step-4-copy-app-credentials" aria-label="Permalink to &quot;Step 4: Copy App Credentials&quot;">​</a></h3><p>Simpan dua nilai ini dari Dropbox app page:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-isi-dropbox-channel" tabindex="-1">Step 5: Isi Dropbox Channel <a class="header-anchor" href="#step-5-isi-dropbox-channel" aria-label="Permalink to &quot;Step 5: Isi Dropbox Channel&quot;">​</a></h3><p>Dalam Upload Settings, pilih <code>Dropbox</code> dan isi:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Apa Yang Perlu Diisi</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mudah dikenali, contohnya <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Biarkan kosong buat masa ini</td></tr><tr><td>Root directory</td><td>Optional. Default ialah <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+o+'" alt="Get token" loading="lazy"></p><h3 id="step-6-dapatkan-refresh-token" tabindex="-1">Step 6: Dapatkan Refresh Token <a class="header-anchor" href="#step-6-dapatkan-refresh-token" aria-label="Permalink to &quot;Step 6: Dapatkan Refresh Token&quot;">​</a></h3><ol><li>Dalam ImgBed, klik <code>Get Token</code>.</li><li>Sign in ke Dropbox account yang mahu disambungkan.</li><li>Approve authorization prompt.</li><li>Callback page akan menunjukkan <code>Refresh Token</code>.</li><li>Copy token tersebut.</li><li>Kembali ke ImgBed dan paste dalam field <code>Refresh Token</code>.</li></ol><p><img src="'+n+'" alt="Copy token" loading="lazy"></p><h2 id="cara-menyemak" tabindex="-1">Cara Menyemak <a class="header-anchor" href="#cara-menyemak" aria-label="Permalink to &quot;Cara Menyemak&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Dropbox channel muncul selepas save.</td></tr><tr><td>Channel switch</td><td>Channel boleh enabled.</td></tr><tr><td>Token saved</td><td>Detail page menunjukkan <code>Refresh Token</code> telah disimpan.</td></tr><tr><td>Upload test</td><td>Test image muncul dalam Dropbox app folder.</td></tr></tbody></table><p>Jika quota limits diaktifkan, klik quota query. Selepas query berjaya, channel card memaparkan used space, total space dan last update time.</p><p><img src="'+r+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed mengatakan configuration incomplete</td><td>Semak <code>App Key</code>, <code>App Secret</code> dan <code>Refresh Token</code> semuanya telah diisi.</td></tr><tr><td>Authorization berjaya tetapi tiada <code>Refresh Token</code></td><td>Klik <code>Get Token</code> sekali lagi dan pastikan offline authorization flow digunakan.</td></tr><tr><td>Upload gagal dengan <code>required scope &#39;files.content.write&#39;</code></td><td>Enable <code>files.content.write</code>, klik <code>Submit</code>, kemudian dapatkan <code>Refresh Token</code> baharu.</td></tr><tr><td>Callback gagal</td><td>Pastikan redirect URI ialah <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Files tidak dijumpai</td><td>Pastikan Dropbox app dicipta dalam mode <code>App folder</code>.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Buka Dropbox App Console</span></span>
<span class="line"><span>-&gt; Cipta app</span></span>
<span class="line"><span>-&gt; Pilih App folder access</span></span>
<span class="line"><span>-&gt; Tambah https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Enable account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; Optional enable files.content.read</span></span>
<span class="line"><span>-&gt; Klik Submit</span></span>
<span class="line"><span>-&gt; Copy App Key dan App Secret</span></span>
<span class="line"><span>-&gt; Isi dalam ImgBed</span></span>
<span class="line"><span>-&gt; Klik Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token dari callback page</span></span>
<span class="line"><span>-&gt; Paste kembali ke ImgBed dan save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const D=i(c,[["render",h]]);export{y as __pageData,D as default};
